    "cases.material_submittal_and_approval.step.submit.out.deadline": "Behövs-senast-datum",
    "cases.material_submittal_and_approval.step.submit.out.submittal": "Skickat underlag",
    "cases.material_submittal_and_approval.step.submit.title": "Skapa underlaget",
    "cases.material_submittal_and_approval.step.submit.what": "Öppna underlaget för produkten du tänker använda, bifoga datablad, prover och certifikat, och ange vilken specifikationspunkt den erbjuds mot. Skicka det till den projektör som ska godkänna det och sätt ett behövs-senast-datum kopplat till när du måste beställa för att hålla tidplanen.",
    "cases.material_submittal_and_approval.step.submit.why": "Att beställa ett material innan det är godkänt är hur du hamnar med en container full av fel produkt och en tvist om vem som betalar. Ett daterat underlag sätter också klockan igång för projektören, så ett sent godkännande som försenar beställningen finns på pränt.",
    "cases.material_submittal_and_approval.title": "Få ett materialunderlag godkänt",
    "cases.milestone_progress_before_drawdown.desc": "Bekräfta att tidplanen verkligen nått sin milstolpe, kontrollera den mot det upparbetade värdet, och godkänn först då den fakturaunderlag som frigör medel mot den.",
    "cases.milestone_progress_before_drawdown.step.approve.in.amount": "Fakturabelopp",
    "cases.milestone_progress_before_drawdown.step.approve.in.ev": "Avläst upparbetat värde",
    "cases.milestone_progress_before_drawdown.step.approve.in.status": "Milstolpestatus",
    "cases.milestone_progress_before_drawdown.step.approve.out.approved": "Godkänd fakturaunderlag",
    "cases.milestone_progress_before_drawdown.step.approve.out.drawdown": "Frigjord utbetalning",
    "cases.milestone_progress_before_drawdown.step.approve.title": "Godkänn fakturaunderlaget",
    "cases.milestone_progress_before_drawdown.step.approve.what": "Godkänn fakturaunderlaget för det belopp som milstolpen och det upparbetade värdet faktiskt stödjer, med anteckning om eventuell delfrigöring mot en milstolpe som fortfarande pågår.",
    "cases.milestone_progress_before_drawdown.step.approve.why": "Ett godkännande grundat i tidplanen och det upparbetade värdet håller när finansiärer eller revisorer frågar vad det baserades på.",
    "cases.milestone_progress_before_drawdown.step.earned.in.milestone": "Bekräftad milstolpe",
    "cases.milestone_progress_before_drawdown.step.earned.in.planned": "Planerat värde",
    "cases.milestone_progress_before_drawdown.step.earned.in.spend": "Kostnad hittills",
    "cases.milestone_progress_before_drawdown.step.earned.out.consistency": "Konsekvenskontroll av begäran",
    "cases.milestone_progress_before_drawdown.step.earned.out.ev": "Avläst upparbetat värde",
    "cases.milestone_progress_before_drawdown.step.earned.title": "Läs av det upparbetade värdet hittills",
    "cases.milestone_progress_before_drawdown.step.earned.what": "Kontrollera det upparbetade värdet hittills mot vad som spenderats och vad som planerats, så att milstolpsbegäran stämmer med den bredare kostnadsbilden.",
    "cases.milestone_progress_before_drawdown.step.earned.why": "En milstolpe kan se uppnådd ut på tidplanen medan kostnads- och upparbetningsbilden berättar en annan historia. Att läsa av båda tillsammans är det som fångar en inkonsekvens innan den betalas.",
    "cases.milestone_progress_before_drawdown.step.milestones.in.claim": "Begärd milstolpe",
    "cases.milestone_progress_before_drawdown.step.milestones.in.schedule": "Projektets tidplan",
    "cases.milestone_progress_before_drawdown.step.milestones.out.progress": "Verifierad framdrift",
    "cases.milestone_progress_before_drawdown.step.milestones.out.status": "Bekräftad milstolpestatus",
    "cases.milestone_progress_before_drawdown.step.milestones.title": "Kontrollera milstolpen mot tidplanen",
    "cases.milestone_progress_before_drawdown.step.milestones.what": "Öppna tidplanen och bekräfta att milstolpen som fakturaunderlaget begärs mot verkligen är uppnådd, inte bara nära.",
    "cases.milestone_progress_before_drawdown.step.milestones.why": "En milstolpe som begärs en vecka för tidigt och betalas mot är pengar frigjorda för arbete som ännu inte är gjort, och det är besvärligt att kräva tillbaka.",
    "cases.milestone_progress_before_drawdown.title": "Kontrollera milstolpens framdrift innan en fakturaunderlag godkänns",
    "cases.model_quality_audit_before_issue.desc": "Kör kontrollerna som fångar en dålig modell innan en beställare eller ett arbetsplatsteam öppnar den: koordinatbas, aktiva kollisioner och komplett klassificering.",
    "cases.model_quality_audit_before_issue.step.base.in.model": "Fackmodell",
    "cases.model_quality_audit_before_issue.step.base.in.origin": "Gemensam origo och rutnät",
    "cases.model_quality_audit_before_issue.step.base.out.aligned": "Origo-anpassad modell",
    "cases.model_quality_audit_before_issue.step.base.out.base": "Bekräftad koordinatbas",
    "cases.model_quality_audit_before_issue.step.base.title": "Kontrollera koordinatbasen",
    "cases.model_quality_audit_before_issue.step.base.what": "Bekräfta att modellen ligger på det gemensamma projektorigot och rutnätet innan någon nedströms mäter eller kollisionskontrollerar mot den.",
    "cases.model_quality_audit_before_issue.step.base.why": "En modell som är några centimeter fel jämfört med den gemensamma basen skadar i tysthet varje kollisionstest och varje mängd som tas ur den senare.",
    "cases.model_quality_audit_before_issue.step.clash.in.model": "Origo-anpassad modell",
