    "cases.model_quality_audit_before_issue.step.classify.out.ready": "Utfärdandeklar modell",
    "cases.model_quality_audit_before_issue.step.classify.out.report": "Valideringsrapport",
    "cases.model_quality_audit_before_issue.step.classify.title": "Bekräfta att klassificeringen är komplett",
    "cases.model_quality_audit_before_issue.step.classify.what": "Kör valideringsreglerna och bekräfta att varje element har den klassificering och egenskapsuppsättning nästa steg förväntar sig, utan någon omappad kategori kvar.",
    "cases.model_quality_audit_before_issue.step.classify.why": "En modell med en lucka i klassificeringen ger nästa användare, en kalkylator eller en entreprenör, ett element de inte kan prissätta eller schemalägga utan att fråga dig först.",
    "cases.model_quality_audit_before_issue.title": "Granska en modell innan den skickas ut",
    "cases.payment_application_and_reconciliation.desc": "Värdera arbetet som utförts under perioden mot kontraktet, skapa fakturaunderlaget med underlag bakom det, och avstäm det du fakturerat mot vad som faktiskt kom in på kontot.",
    "cases.payment_application_and_reconciliation.step.apply.in.materials": "Material på plats",
    "cases.payment_application_and_reconciliation.step.apply.in.sum": "Bekräftad kontraktssumma",
    "cases.payment_application_and_reconciliation.step.apply.in.work": "Utfört arbete denna period",
    "cases.payment_application_and_reconciliation.step.apply.out.application": "Fakturaunderlag",
    "cases.payment_application_and_reconciliation.step.apply.out.evidence": "Styrkande underlag",
    "cases.payment_application_and_reconciliation.step.apply.title": "Skapa fakturaunderlaget",
    "cases.payment_application_and_reconciliation.step.apply.what": "Mät det arbete som utförts denna period, lägg till material som behörigen finns på plats och godkända ändringar, och dra sedan av innehållen summa och allt som redan betalats innan du skickar fakturaunderlaget.",
    "cases.payment_application_and_reconciliation.step.apply.why": "Kassaflöde är syret i ett byggföretag, och underentreprenörer märker en sen faktura först. Ett underlag som är tydligt och fullt styrkt är det som blir godkänt på förfallodagen.",
    "cases.payment_application_and_reconciliation.step.contract.in.contract": "Signerat kontrakt",
    "cases.payment_application_and_reconciliation.step.contract.in.terms": "Innehållen summa och villkor",
