    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.level-crews.out.histogram": "Utjämnade arbetstoppar",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.level-crews.out.levelled": "Utjämnade lag",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.level-crews.title": "Jämna ut lagen efter takten",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.level-crews.what": "Dimensionera och jämna ut lagen så att varje yrkesgrupp kan avsluta sin zon inom takttiden, utan en topp de inte kan bemanna.",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.level-crews.why": "Om ett lag inte kan hålla takten stannar hela tåget bakom det. Att jämna ut tidigt är billigare än att jaga arbetskraft på byggarbetsplatsen.",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.publish.in.plan": "Utjämnad taktplan",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.publish.in.trades": "Yrkesgruppernas kontaktuppgifter",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.publish.out.dates": "Zondatum per yrkesgrupp",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.publish.out.lob": "Publicerad balanslinje",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.publish.title": "Publicera planen till yrkesgrupperna",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.publish.what": "Publicera taktplanen och ge varje yrkesgrupp sina zoner och datum.",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.publish.why": "En taktplan fungerar bara när varje förman känner till sin takt. Att publicera den sätter den gemensamma rytmen hela jobbet arbetar efter.",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.takt-time.in.durations": "Aktivitetstider",
