    "cases.prepare_an_interim_payment_application.step.retention.in.rate": "Innehållandeprocent",
    "cases.prepare_an_interim_payment_application.step.retention.out.net": "Nettobelopp att betala",
    "cases.prepare_an_interim_payment_application.step.retention.out.retention": "Innehållen summa",
    "cases.prepare_an_interim_payment_application.step.retention.title": "Tillämpa innehållen summa och tidigare betalningar",
    "cases.prepare_an_interim_payment_application.step.retention.what": "Ta bruttovärdet, håll inne enligt kontraktets procentsats, dra av det som redan certifierats på tidigare fakturaunderlag, och saldot är nettobeloppet detta underlag begär.",
    "cases.prepare_an_interim_payment_application.step.retention.why": "Att få innehållen summa och tidigare betalningar rätt är skillnaden mellan ett underlag som godkänns rent och ett som studsar tillbaka för korrigering och missar betalningsperioden.",
    "cases.prepare_an_interim_payment_application.step.value.in.measured": "Uppmätt arbete",
