    "finance.send_for_approval_failed": "Det gick inte att skicka fakturan för godkännande",
    "finance.send_for_approval_hint": "Flytta den här utkastfakturan till väntande så att en chef kan godkänna den.",
    "finance.status_current": "aktuell",
    "finance.status_edit_hint": "Flytta fakturan mellan utkast, väntande och annullerad. Att godkänna en faktura och markera den som betald görs med knapparna Godkänn och Markera som betald på fakturaraden.",
    "finance.status_label": "Status",
    "geo_hub.empty.no_anchor_description_v2": "Förankra automatiskt utifrån adressen du angett i projektinställningarna, eller välj en koordinat manuellt. Du kan finjustera genom att dra när nålen har placerats.",
    "geo_hub.empty.no_anchor_description_v3": "Förankra automatiskt utifrån adressen du angett i projektinställningarna, eller placera en nål direkt på kartan. Du kan finjustera genom att dra när nålen har placerats.",
    "geo_hub.empty.place_manually_cta": "Placera en nål på kartan",
    "geo_hub.place_anchor.instruction": "Klicka på kartan för att placera det här projektet",
    "geo_hub.place_anchor.locating": "Lokaliserar det här projektet utifrån dess adress...",
    "projects.no_archived_hint": "Inga arkiverade projekt. Växla tillbaka till aktiva projekt nedan.",
