    "whatsnew.v820.fixes.chip": "Korrigeringar",
    "whatsnew.v820.fixes.b1": "En kommentar som bär en vy kontrollerar nu sin entitetstyp mot samma tillåtelselista som den fristående vägen.",
    "whatsnew.v820.fixes.b2": "Förhandsvisningar av DWG-ritningar renderas igen på nyare ezdxf-versioner, version 1.1 och senare.",
    "takeoff.needs_ocr_banner": "{{n}} av {{total}} sidor saknar textlager och behöver troligen OCR.",
